import { apply } from "@universal-middleware/fastify";
import vikeMiddleware from "vike/universal-middleware";
import { toFetchHandler } from "srvx/node";
export * from "@universal-middleware/fastify";
//#region src/index.ts
function vike(app, middlewares = []) {
	return apply(app, [...middlewares, vikeMiddleware]);
}
//#endregion
export { vike as default, toFetchHandler };
